package com.example.ppm.controller;import com.example.ppm.common.R;import com.example.ppm.dto.attachment.AttachmentResponse;import com.example.ppm.service.AttachmentService;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import java.util.*;
@RestController public class AttachmentController{private final AttachmentService s;public AttachmentController(AttachmentService s){this.s=s;}@PostMapping("/api/attachments")public R<AttachmentResponse>up(@RequestParam MultipartFile file,@RequestParam(required=false)String kind){return R.ok(s.upload(file,kind));}@GetMapping("/api/tasks/{id}/attachments")public R<List<AttachmentResponse>>list(@PathVariable Long id){return R.ok(s.list(id));}@DeleteMapping("/api/attachments/{id}")public R<Void>del(@PathVariable Long id){s.remove(id);return R.ok();}}
